        },
        {
          "questionText": "What is the SI unit for Frequency (f), which measures cycles per second?",
          "answerGuidance": [
            "Hertz",
            "Hz",
            "Unit for AC cycles"
          ]
        }
      ],
      "deeperQuestionText": "Based on the explanation, why must an electrician distinguish between Power (P) and Energy when recording technical data?",
      "deeperAnswerGuidance": [
        "They represent different physical concepts",
        "Power is the rate of use measured in Watts",
        "Energy is the total amount used measured in Joules",
        "Using the wrong unit would lead to inaccurate technical communication"
      ],
      "hint": "Consider the difference between the 'rate' of use and the 'total amount' used."
    }
  ]
}

